','%s option reset'=>'Option %s zurückgesetzt','Please specify if you would like to disconnect a blog or user.'=>'Bitte geben Sie an, ob Sie einen Blog oder Benutzer trennen möchten.','User has been successfully disconnected.'=>'Benutzer wurde erfolgreich getrennt.','Jetpack has been successfully disconnected for %s.'=>'Die Jetpack-Verbindung für %s wurde erfolgreich getrennt. ','Please specify a user by either ID, username, or email.'=>'Bitte geben Sie einen Benutzer anhand seiner ID, seines Benutzernamens oder seiner E-Mail-Adresse an.','Please specify a valid user.'=>'Geben Sie einen gültigen Benutzer an.','"wp jetpack status full" is a command - do not translateView full status with \'wp jetpack status full\''=>'Mit "wp jetpack status full" können Sie den vollständigen Status anzeigen.','Additional data: '=>'Zusätzliche Daten:','The WordPress.com blog_id is %d'=>'Die WordPress.com-Blog-ID lautet %d','The Jetpack Version is %s'=>'Die Jetpack Version ist %s','Jetpack is currently connected to WordPress.com'=>'Jetpack ist momentan mit WordPress.com verbunden','%s is not a valid command.'=>'%s ist kein gültiger Befehl.','Jetpack is not currently connected to WordPress.com'=>'Jetpack ist momentan nicht mit WordPress.com verbunden','Configure'=>'Konfigurieren','Popular'=>'Beliebt','Newest'=>'Neueste','Alphabetical'=>'Alphabetisch','Inactive'=>'Inaktiv','Active'=>'Aktiv','All'=>'Alle','Search'=>'Suchen','Jetpack Settings'=>'Jetpack-Einstellungen','My Jetpack'=>'Mein Jetpack','Feedback'=>'Rückmeldung','Settings'=>'Einstellungen','Jetpack'=>'Jetpack','Learn More'=>'Mehr erfahren','Support'=>'Support','Test your site\'s compatibility with Jetpack.'=>'Testen Sie, ob Ihre Website mit Jetpack kompatibel ist.','Privacy'=>'Datenschutz']];